windowclass.script:
			function update()
				local bReadOnly = WindowManager.getReadOnlyState(getDatabaseNode());
				
				WindowManager.callSafeControlUpdate(self, "realm", bReadOnly);
				self["realm"].setComboBoxReadOnly(bReadOnly);
				WindowManager.callSafeControlUpdate(self, "category", bReadOnly);
				self["category"].setComboBoxReadOnly(bReadOnly);
				WindowManager.callSafeControlUpdate(self, "primerequisite1", bReadOnly);
				self["primerequisite1"].setComboBoxReadOnly(bReadOnly);
				WindowManager.callSafeControlUpdate(self, "primerequisite2", bReadOnly);
				self["primerequisite2"].setComboBoxReadOnly(bReadOnly);
				WindowManager.callSafeControlUpdate(self, "primerequisite3", bReadOnly);
				self["primerequisite3"].setComboBoxReadOnly(bReadOnly);
					
				base_spelllists.update(bReadOnly);

				description.setReadOnly(bReadOnly);
			end
			
			function updateDropDown(sControl, sDropDown)
				if self[sControl].isReadOnly() then
					self[sDropDown].setVisible(false);
				else
					self[sDropDown].setVisible(true);
				end	
			end

combobox_columnh_campaign.script:
function onInit()
	super.onInit();
	addItems(Rules_Realm.List());
	add("Pick One");
end

header_column.script:
function onInit()
	if Session.IsHost then
		setTooltipText(Interface.getString("profession_tooltip_base_spell_lists"));
	end
end

function onDrop(x, y, draginfo)
	window.base_spelllists.onDrop(x, y, draginfo);
end

list_column.script:
					function onListChanged()
						super.onListChanged();
						
						local bLocked = WindowManager.getLockedState(DB.getParent(getDatabaseNode()));
						if bLocked then
							window.base_spelllists_iedit.setVisible(false);
						else
							if getWindowCount() > 0 then
								window.base_spelllists_iedit.setVisible(true);
							else
								window.base_spelllists_iedit.setVisible(false);
							end		
						end
					end
					
					function onDrop(x, y, draginfo)
						local bLocked = WindowManager.getLockedState(DB.getParent(getDatabaseNode()));
						if not bLocked then
							if draginfo.isType("spelllist") then
								local win = draginfo.getCustomData();
								local source = win.getDatabaseNode();
								addSpellList(source);
								return true;
							elseif draginfo.isType("shortcut") then
								local class = draginfo.getShortcutData();
								local source = draginfo.getDatabaseNode();
								if source and class == "spelllist" then
									addSpellList(source);
									return true;
								end
							end
						end
						return false;
					end

					function addSpellList(source)
						local newentry;
						local newnode;

						local newname = DB.getValue(source, "name", "");
						if newname ~= "" then
							for i,win in ipairs(getWindows()) do
								if win.name.getValue() == newname then
									--[[ duplicate, warn the user and fail ]]
									Comm.deliverChatMessage({font="systemfont",text="Spell list '" .. newname .. "' is already a known base list"});
									return nil;
								end
							end
						end

						newentry = createWindow();
						newnode = newentry.getDatabaseNode();

						--[[ Descriptive fields ]]
						local sSpellListName = DB.getValue(source, "name", "");
						newentry.name.setValue(sSpellListName);

						--[[ Shortcut ]]
						newentry.open.setTarget(DB.getPath(source));

						return newentry;
					end

windowclass.script:
function update()
	local bReadOnly = WindowManager.getReadOnlyState(getDatabaseNode());
	
	primary_skill_costs.setReadOnly(bReadOnly);
	for i, win in ipairs(primary_skill_costs.getWindows()) do
		win.cost.setReadOnly(bReadOnly);
	end
end

list_column_prof_skillcost.script:
					function onInit()
						super.onInit();

						if Session.IsHost then
							Module.onModuleLoad = updateSkillList;
						end
						
						updateSkillList();
					end
					
					function updateSkillList()			
						local sProfessionName = DB.getValue(window.getDatabaseNode(), "name", "");
						local listSkillCost = Rules_Professions.SkillCostList("Primary", sProfessionName);

						for k, vSkillCost in pairs(listSkillCost) do
							bFound = false;
							for i, winSkillCost in ipairs(getWindows()) do
								if vSkillCost.SkillName == winSkillCost.name.getValue() then
									bFound = true;
								end
								local _, sRecordName = winSkillCost.open.getValue();
								local nodeSkill = DB.findNode(sRecordName);
								if nodeSkill then
									if string.lower(DB.getValue(nodeSkill, "class", "")) == "secondary" then
										WindowManager.safeDelete(winSkillCost);
									end
								end
							end
							
							if not bFound then
								local newentry = createWindow();

								--[[ Descriptive fields ]]
								if vSkillCost.SkillName then
									newentry.name.setValue(vSkillCost.SkillName);
								end
								if vSkillCost.SkillCost then
									newentry.cost.setValue(vSkillCost.SkillCost);
								end

								--[[ Shortcut ]]
								newentry.open.setValue("skill",vSkillCost.NodeName);
								newentry.open.setVisible(true);

								--[[ re-initialise 
								newentry.onInit(); ]]
							end
							
						end
					end

