windowclass.script:
function onInit()
	if super and super.onInit then
		super.onInit();
	end
	local node = getDatabaseNode();    
	if not open.getValue() then
		open.setValue("skill", DB.getPath(node));
	end
	open.setVisible(true);
end

function update()
	local bReadOnly = WindowManager.getReadOnlyState(getDatabaseNode());
	
	level_bonuses_core.setReadOnly(bReadOnly);
	for i, win in ipairs(level_bonuses_core.getWindows()) do
		win.bonus.setReadOnly(bReadOnly);
	end
	level_bonuses_rm2.setReadOnly(bReadOnly);
